/**
 * QTI Code Panel - UI Component
 *
 * Displays editor document as HTML, JSON, or XML.
 * Listens to code update events from the qtiCodePanelExtension.
 * Customize styling as needed.
 */

import { html, LitElement, type TemplateResult } from 'lit';
import { customElement } from 'lit/decorators.js';
import type { QtiCodeUpdateDetail } from '@qti-editor/core/code';

type CodeMode = 'html' | 'json' | 'xml';

@customElement('qti-code-panel')
export class QtiCodePanel extends LitElement {
  private _eventName = 'qti:code:update';
  private _eventTarget: EventTarget | null = null;
  private _mode: CodeMode = 'html';
  private currentEventTarget: EventTarget | null = null;

  private detail: QtiCodeUpdateDetail | null = null;

  get eventName() {
    return this._eventName;
  }

  set eventName(value: string) {
    const next = value || 'qti:code:update';
    if (this._eventName === next) return;
    const prev = this._eventName;
    this._eventName = next;
    this.updateEventListener(prev, this._eventName, this._eventTarget);
  }

  get eventTarget() {
    return this._eventTarget;
  }

  set eventTarget(value: EventTarget | null) {
    if (this._eventTarget === value) return;
    this._eventTarget = value;
    this.updateEventListener(this._eventName, this._eventName, this._eventTarget);
  }

  get mode() {
    return this._mode;
  }

  set mode(value: CodeMode) {
    if (this._mode === value) return;
    this._mode = value;
    this.requestUpdate();
  }

  private readonly onUpdateEvent = (event: Event) => {
    this.detail = (event as CustomEvent<QtiCodeUpdateDetail>).detail ?? null;
    this.requestUpdate();
  };

  override createRenderRoot() {
    return this;
  }

  connectedCallback() {
    super.connectedCallback();
    this.currentEventTarget = this.getEventTarget();
    this.currentEventTarget.addEventListener(this.eventName, this.onUpdateEvent as EventListener);
  }

  disconnectedCallback() {
    if (this.currentEventTarget) {
      this.currentEventTarget.removeEventListener(
        this.eventName,
        this.onUpdateEvent as EventListener,
      );
    }
    super.disconnectedCallback();
  }

  private updateEventListener(
    prevEventName: string,
    nextEventName: string,
    nextTarget: EventTarget | null,
  ) {
    if (!this.isConnected) return;
    const target = nextTarget ?? document;
    const prevTarget = this.currentEventTarget ?? target;
    if (prevTarget) {
      prevTarget.removeEventListener(prevEventName, this.onUpdateEvent as EventListener);
    }
    target.addEventListener(nextEventName, this.onUpdateEvent as EventListener);
    this.currentEventTarget = target;
  }

  private getEventTarget(): EventTarget {
    return this._eventTarget ?? document;
  }

  private renderToolbar(): TemplateResult {
    return html`
      <div class="flex w-full items-center justify-between gap-3 border-b border-base-300/40 pb-3 mb-3">
        <div class="text-[0.95rem] font-bold">Generated Code</div>
        <div class="join">
          <button
            class=${this._mode === 'html'
              ? 'btn btn-xs sm:btn-sm join-item normal-case font-semibold btn-info'
              : 'btn btn-xs sm:btn-sm join-item normal-case font-semibold btn-ghost border border-base-300/60 bg-base-100 text-base-content'}
            @click=${() => (this.mode = 'html')}
          >
            HTML
          </button>
          <button
            class=${this._mode === 'json'
              ? 'btn btn-xs sm:btn-sm join-item normal-case font-semibold btn-info'
              : 'btn btn-xs sm:btn-sm join-item normal-case font-semibold btn-ghost border border-base-300/60 bg-base-100 text-base-content'}
            @click=${() => (this.mode = 'json')}
          >
            JSON
          </button>
          <button
            class=${this._mode === 'xml'
              ? 'btn btn-xs sm:btn-sm join-item normal-case font-semibold btn-info'
              : 'btn btn-xs sm:btn-sm join-item normal-case font-semibold btn-ghost border border-base-300/60 bg-base-100 text-base-content'}
            @click=${() => (this.mode = 'xml')}
          >
            XML
          </button>
        </div>
      </div>
    `;
  }

  render() {
    const htmlText = this.detail?.html ?? '';
    const jsonText = this.detail?.json
      ? JSON.stringify(this.detail.json, null, 2)
      : '';
    const xmlText = this.detail?.xml ?? '';
    const displayText = this._mode === 'html'
      ? this.formatHtml(htmlText)
      : this._mode === 'json'
        ? jsonText
        : xmlText;

    return html`
      <section
        class="card ${this.detail
          ? 'opacity-100 translate-y-0'
          : 'opacity-70 translate-y-2'}"
      >
        ${this.renderToolbar()}
        <pre class="m-0 max-h-80 max-w-full overflow-auto rounded-xl bg-neutral p-3 text-xs text-neutral-content whitespace-pre break-normal">${displayText || 'No content yet.'}</pre>
      </section>
    `;
  }

  private formatHtml(html: string): string {
    let formatted = '';
    let indent = 0;
    const indentStr = '  ';
    const parts = html.split(/(<[^>]+>)/g).filter((part) => part.trim());

    for (const part of parts) {
      if (part.startsWith('</')) {
        indent = Math.max(0, indent - 1);
        formatted += indentStr.repeat(indent) + part + '\n';
      } else if (part.startsWith('<') && !part.endsWith('/>')) {
        formatted += indentStr.repeat(indent) + part + '\n';
        indent++;
      } else if (part.startsWith('<') && part.endsWith('/>')) {
        formatted += indentStr.repeat(indent) + part + '\n';
      } else {
        formatted += indentStr.repeat(indent) + part.trim() + '\n';
      }
    }

    return formatted.trim();
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'qti-code-panel': QtiCodePanel;
  }
}

/**
 * QTI Code Panel Example - Entry Point
 *
 * Re-exports all parts needed for the code panel example.
 */

// Core types and functions
export type {
  QtiCodePanelOptions,
  QtiCodeUpdateDetail,
  QtiDocumentJson,
  QtiNodeJson,
} from '@qti-editor/core/code';

export { qtiCodePanelExtension } from '@qti-editor/core/code';

// Extension configuration
export { defineExtension, type CodePanelExtensionOptions } from './extension.js';

// Editor example
export { LitEditorCodePanel, registerLitEditorCodePanel } from './editor.js';

// UI component
export { QtiCodePanel } from '../../ui/qti-code-panel/index.js';

/**
 * QTI Code Panel Extension Configuration
 *
 * This file shows how to configure the qtiCodePanelExtension for your editor.
 */

import { union, type Extension } from 'prosekit/core';
import { qtiCodePanelExtension, type QtiCodePanelOptions } from '@qti-editor/core/code';

export interface CodePanelExtensionOptions extends QtiCodePanelOptions {
  // Add any additional options specific to this example
}

/**
 * Returns the extension configured for the code panel example.
 * Customize the options to match your editor's needs.
 */
export function defineExtension(options: CodePanelExtensionOptions = {}): Extension {
  return union(
    qtiCodePanelExtension({
      eventName: options.eventName ?? 'qti:code:update',
      eventTarget: options.eventTarget ?? document,
      emitOnInit: options.emitOnInit ?? true,
    }),
  );
}

export type { QtiCodePanelOptions } from '@qti-editor/core/code';

/**
 * QTI Code Panel Editor Example
 *
 * This file demonstrates how to integrate the QtiCodePanel
 * component with a ProseKit editor.
 */

import '../../ui/qti-code-panel/index.js';

import { html, LitElement, type PropertyDeclaration, type PropertyValues } from 'lit';
import { createRef, ref, type Ref } from 'lit/directives/ref.js';
import { union, type Editor } from 'prosekit/core';
import { createEditor } from 'prosekit/core';
import { defineBasicExtension } from 'prosekit/basic';

import { defineExtension } from './extension.js';

export class LitEditorCodePanel extends LitElement {
  static override properties = {
    editor: {
      state: true,
      attribute: false,
    } satisfies PropertyDeclaration<Editor>,
  };

  private editor: Editor;
  private editorRef: Ref<HTMLDivElement>;

  constructor() {
    super();

    // Combine the basic editor extension with the code panel extension
    const extension = union(defineBasicExtension(), defineExtension());
    this.editor = createEditor({ extension });
    this.editorRef = createRef<HTMLDivElement>();
  }

  override createRenderRoot() {
    return this;
  }

  override disconnectedCallback() {
    this.editor.unmount();
    super.disconnectedCallback();
  }

  override updated(changedProperties: PropertyValues) {
    super.updated(changedProperties);
    this.editor.mount(this.editorRef.value);
  }

  override render() {
    return html`
      <div class="flex gap-4">
        <div class="flex-1">
          <div class="prose" ${ref(this.editorRef)}></div>
        </div>
        <div class="w-96">
          <qti-code-panel></qti-code-panel>
        </div>
      </div>
    `;
  }
}

export function registerLitEditorCodePanel() {
  if (!customElements.get('lit-editor-code-panel')) {
    customElements.define('lit-editor-code-panel', LitEditorCodePanel);
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'lit-editor-code-panel': LitEditorCodePanel;
  }
}
